from claude_agent_sdk import query, ClaudeAgentOptions, AgentDefinition

async for message in query(
    prompt="Revisá el módulo de autenticación en busca de problemas de seguridad",
    options=ClaudeAgentOptions(
        allowed_tools=["Read", "Grep", "Glob", "Agent"],
        agents={
            "code-reviewer": AgentDefinition(
                description="Especialista en code review. Usar para calidad, seguridad y mantenibilidad.",
                prompt="""Sos un especialista en code review. Al revisar código:
- Identificá vulnerabilidades de seguridad
- Verificá adherencia a estándares
- Sugerí mejoras concretas""",
                tools=["Read", "Grep", "Glob"],
                model="sonnet",
            ),
        },
    ),
):
    if hasattr(message, "result"):
        print(message.result)

async for message in query(prompt="...", options=options):
    # Detectar cuando se invoca un subagente
    if hasattr(message, "content") and message.content:
        for block in message.content:
            # La herramienta se llama "Agent" (versiones SDK antiguas usaban "Task")
            if getattr(block, "type", None) == "tool_use" and block.name in ("Task", "Agent"):
                print(f"Subagente invocado: {block.input.get('subagent_type')}")

    # Detectar mensajes que provienen DESDE dentro de un subagente
    if hasattr(message, "parent_tool_use_id") and message.parent_tool_use_id:
        print("  → (mensaje originado dentro del subagente)")

def create_security_agent(level: str) -> AgentDefinition:
    return AgentDefinition(
        description="Revisor de seguridad especializado",
        prompt=f"Sos un revisor de seguridad {'estricto (OWASP Top 10 + SANS)' if level == 'strict' else 'balanceado'}...",
        tools=["Read", "Grep", "Glob"],
        # Opus para revisiones estrictas, Sonnet para las regulares
        model="opus" if level == "strict" else "sonnet",
    )

# Uso:
agents={"security-reviewer": create_security_agent("strict")}
